Graph& Graph::operator=(const Graph& other) {
    if (this != &other) {
        type_ = other.type_;
        nodes_ = other.nodes_;
        adj_ = other.adj_;
        radj_ = other.radj_;
        edge_index_ = other.edge_index_;
        next_node_id_ = other.next_node_id_;
        next_edge_id_ = other.next_edge_id_;
        edge_count_ = other.edge_count_;
