}

Graph::Graph(Graph&& other) noexcept
    : type_(other.type_), nodes_(std::move(other.nodes_)),
      adj_(std::move(other.adj_)), radj_(std::move(other.radj_)),
      edge_index_(std::move(other.edge_index_)),
