                if (e.dst == dst) {
                    removed_ids.push_back(e.id);
                    edge_index_.erase(e.id);
                    edge_count_--;
                    return true;
                }
                return false;
            }),
        edges.end());

    // Clean radj_[dst]
    auto& rev_dst = radj_[dst];
    rev_dst.erase(
        std::remove_if(rev_dst.begin(), rev_dst.end(),
            [&removed_ids](const Edge& e) {
                for (auto eid : removed_ids) { if (e.id == eid) return true; }
