        std::vector<EdgeId> rev_removed_ids;
        auto& redges = radj_it->second;
        redges.erase(
            std::remove_if(redges.begin(), redges.end(),
                [src, this, &rev_removed_ids](const Edge& e) {
                    if (e.dst == src) {
                        rev_removed_ids.push_back(e.id);
