                    for (auto eid : rev_removed_ids) { if (e.id == eid) return true; }
                    return false;
                }),
            rev_src.end());
    }
}

bool Graph::has_edge(NodeId src, NodeId dst) const {
    auto it = adj_.find(src);
    if (it == adj_.end()) return false;
    for (auto& e : it->second) {
