#include "test_framework.hpp"
#include "flow/flow.hpp"

#include <unordered_set>

using namespace cryo;
using namespace cryo_test;

namespace {

double cut_edge_capacity(const MinCutResult& cut) {
    double total = 0.0;
    for (const auto& edge : cut.cut_edges) {
        total += edge.weight;
    }
    return total;
}

void assert_partition_covers_graph(const Graph& g, const MinCutResult& cut,
                                   NodeId source, NodeId sink) {
    for (NodeId node : g.node_ids()) {
        const bool in_source = cut.source_side.count(node) > 0;
        const bool in_sink = cut.sink_side.count(node) > 0;
        assert_ne(in_source, in_sink, "node must be in exactly one cut side");
    }

    assert_true(cut.source_side.count(source) > 0, "source must be on source side");
    assert_true(cut.sink_side.count(sink) > 0, "sink must be on sink side");
    assert_eq(cut.source_side.size() + cut.sink_side.size(), g.node_count(),
              "partition must cover every node");
}

void assert_cut_edges_are_exact_crossing_edges(const Graph& g, const MinCutResult& cut) {
    std::unordered_set<EdgeId> expected;
    g.for_each_edge([&](const Edge& edge) {
        if (cut.source_side.count(edge.src) > 0 && cut.sink_side.count(edge.dst) > 0) {
            expected.insert(edge.id);
        }
    });

    std::unordered_set<EdgeId> actual;
    for (const auto& edge : cut.cut_edges) {
        assert_true(cut.source_side.count(edge.src) > 0,
                    "cut edge must start on source side");
        assert_true(cut.sink_side.count(edge.dst) > 0,
                    "cut edge must end on sink side");
        actual.insert(edge.id);
    }

    assert_eq(actual.size(), expected.size(), "cut edge count must match crossing edges");
    for (EdgeId edge_id : expected) {
        assert_true(actual.count(edge_id) > 0, "missing crossing edge from cut_edges");
    }
}

void assert_min_cut_invariants(const Graph& g, const MinCutResult& cut,
                               NodeId source, NodeId sink) {
    assert_partition_covers_graph(g, cut, source, sink);
    assert_cut_edges_are_exact_crossing_edges(g, cut);
    assert_near(cut_edge_capacity(cut), cut.cut_value, 1e-9,
                "cut edge capacity must equal cut value");
    assert_near(cut.cut_value, max_flow_value(g, source, sink), 1e-9,
                "min cut value must equal max flow");
}

} // namespace

CRYO_TEST(Flow, MinCutSaturatedEdgeDoesNotLeakSinkSide) {
    Graph g(GraphType::Directed);
    for (int i = 0; i < 3; i++) g.add_node_with_id(i);
    g.add_edge(0, 1, 1.0);
    g.add_edge(1, 2, 1.0);

    auto cut = min_cut(g, 0, 2);

    assert_min_cut_invariants(g, cut, 0, 2);
    assert_eq(cut.source_side.size(), (size_t)1);
    assert_true(cut.source_side.count(0) > 0);
    assert_eq(cut.sink_side.size(), (size_t)2);
    assert_true(cut.sink_side.count(1) > 0);
    assert_true(cut.sink_side.count(2) > 0);
    assert_eq(cut.cut_edges.size(), (size_t)1);
    assert_eq(cut.cut_edges[0].src, (NodeId)0);
    assert_eq(cut.cut_edges[0].dst, (NodeId)1);
}

CRYO_TEST(Flow, MinCutUsesReverseResidualReachability) {
    Graph g(GraphType::Directed);
    for (int i = 0; i < 5; i++) g.add_node_with_id(i);
    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 1.0);
    g.add_edge(1, 3, 1.0);
    g.add_edge(2, 3, 1.0);
    g.add_edge(3, 4, 1.0);

    auto cut = min_cut(g, 0, 4);

    assert_min_cut_invariants(g, cut, 0, 4);
    assert_eq(cut.source_side.size(), (size_t)4);
    assert_true(cut.source_side.count(0) > 0);
    assert_true(cut.source_side.count(1) > 0);
    assert_true(cut.source_side.count(2) > 0);
    assert_true(cut.source_side.count(3) > 0);
    assert_eq(cut.sink_side.size(), (size_t)1);
    assert_true(cut.sink_side.count(4) > 0);
    assert_eq(cut.cut_edges.size(), (size_t)1);
    assert_eq(cut.cut_edges[0].src, (NodeId)3);
    assert_eq(cut.cut_edges[0].dst, (NodeId)4);
}

CRYO_TEST(Flow, MinCutPlacesDisconnectedUnreachableNodesOnSinkSide) {
    Graph g(GraphType::Directed);
    for (int i = 0; i < 4; i++) g.add_node_with_id(i);
    g.add_edge(0, 2, 5.0);

    auto cut = min_cut(g, 0, 1);

    assert_min_cut_invariants(g, cut, 0, 1);
    assert_eq(cut.source_side.size(), (size_t)2);
    assert_true(cut.source_side.count(0) > 0);
    assert_true(cut.source_side.count(2) > 0);
    assert_eq(cut.sink_side.size(), (size_t)2);
    assert_true(cut.sink_side.count(1) > 0);
    assert_true(cut.sink_side.count(3) > 0);
    assert_eq(cut.cut_edges.size(), (size_t)0);
    assert_near(cut.cut_value, 0.0);
}

